css:
.loader {
  display: inline-block;
  width: 72px;
  height: 3px;
  overflow: hidden;
  border-radius: 999px;
  background: rgba(99, 102, 241, 0.18);
}
.loader::before {
  content: "";
  display: block;
  width: 36%;
  height: 100%;
  border-radius: inherit;
  background: #6366f1;
  animation: line 0.9s ease-in-out infinite;
}
@keyframes line {
  0% { transform: translateX(-110%); }
  100% { transform: translateX(290%); }
}
